class Solution {
    public boolean doesAliceWin(String s) {
        return helper(s, 0, s.length() - 1, true);
    }
    private boolean helper(String s, int left, int right, boolean aliceTurn) {
        if (left > right) {
            return false;
        }
        int vowels = 0;
        for (int i = left; i <= right; i++) {
            if (isVowel(s.charAt(i))) {
                vowels++;
            }
        }
        if (aliceTurn && vowels % 2 != 0) {
            return true;
        }
        if (!aliceTurn && vowels % 2 == 0) {
            return true;
        }
        return helper(s, left + 1, right, !aliceTurn) || helper(s, left, right - 1, !aliceTurn);
    }
    private boolean isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }
}
